  const renderMarketplaceContent = () => {
    if (!marketplaceContent) return null;

    return (
      <>
        <Text
          type="paragraphXL"
          color="BRAND_COMPLEMENT_01"
          mb="xxxxs"
          mt="xxxxs"
        >
          Número do pedido
        </Text>
        <Text type="paragraphMD" color="INTENSE_COLOR_03">
          #{marketplaceContent.orderNumber}
        </Text>
        {marketplaceContent.status && (
          <>
            {renderDivider()}
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Status do pedido
            </Text>
            <TagLabel
              type={(marketplaceContent.statusColor as never) || 'neutral'}
              text={marketplaceContent.status}
              showSpacing
            />
          </>
        )}
        {marketplaceContent.paymentType && (
          <>
            {renderDivider()}
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Forma de pagamento
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {marketplaceContent.paymentType}
            </Text>
          </>
        )}
        {marketplaceContent.shippingValuePoints !== undefined &&
          marketplaceContent.shippingValuePoints !== null && (
            <>
              {renderDivider()}
              <Text
                type="paragraphXL"
                color="BRAND_COMPLEMENT_01"
                mb="xxxxs"
                mt="xxxxs"
              >
                Frete
              </Text>
              <Text type="paragraphMD" color="INTENSE_COLOR_03">
                {marketplaceContent.shippingValuePoints}
              </Text>
            </>
          )}
        {marketplaceContent.valuePoints !== undefined &&
          marketplaceContent.valuePoints !== null && (
            <>
              {renderDivider()}
              <Text
                type="paragraphXL"
                color="BRAND_COMPLEMENT_01"
                mb="xxxxs"
                mt="xxxxs"
              >
                Valor total
              </Text>
              <Text type="paragraphMD" color="INTENSE_COLOR_03">
                {marketplaceContent.valuePoints}
              </Text>
            </>
          )}
        {marketplaceContent.vendorName && (
          <>
            {renderDivider()}
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Parceiro: {marketplaceContent.vendorName}
            </Text>
          </>
        )}
        {marketplaceContent.items.map((item, itemIndex: number) => (
          <CardActivity
            key={itemIndex}
            mt="nano"
            title={item.name}
            titleTextType="paragraphMD"
            description={`Quantidade: ${item.quantity}\nValor: ${item.valuePoints}`}
            descriptionTextType="paragraphSM"
