              type="paragraphXXXL"
              color="BRAND_COMPLEMENT_01"
              mb="xs"
              align="center"
            >
              Central de Atendimento
            </Text>
          </Box>
        </Box>

        <Box pd="innerSmall">
          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Capitais"
            description="4002 1552"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_capitais',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });
              Linking.openURL('tel:40021552');
            }}
          />

          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Demais localidades"
            description="0800 015 0252"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_demais_localidades',
                location_1: 'monetizacao',
